@js:
result = result
    .replace(/^🗣\s*音色：.*$/gm, function(line) {
        return "🗣 音色：" + reMulti(line.replace(/^🗣\s*音色：/, ""));
    })
    .replace(/^✨\s*当前音色：(\d+)$/gm, function(_, n) {
        return "✨ 当前音色：" + reSingle(n);
    })
    .replace(/.+：(人在读)?\n/g, "")
    .replace('__status__', (java.getString('$.book_search_visible') == 'true' ? '正常' : (java.getString('$.tomato_book_status') == '3' ? '下架' : '小黑屋')))

