    tab = 2
    setArguments('type','audio')
    key = key.slice(2)
}
if (String(key).startsWith("d:") || String(key).startsWith("d：")) {
    tab = 11
    setArguments('type','video')
    key = key.slice(2)
}
if (String(key).startsWith("x:") || String(key).startsWith("x：")) {
    tab = 3
    setArguments('type','novel')
    key = key.slice(2)
}
