function getArguments(open_argument, key) {
    try {
        open_argument = JSON.parse(open_argument);
    } catch (e) {
        open_argument = {
            server: host[0],
            source: "番茄",
            tab: "小说",
            mode: 3,
            searchTab: "小说",
            tone_id: "0"
        };
    }

    // 确保searchTab存在
    if (open_argument.searchTab === undefined) {
        open_argument.searchTab = open_argument.tab || "小说";
    }

    // 确保tone_id存在
    if (open_argument.tone_id === undefined) {
        open_argument.tone_id = "0";
    }

    if (key) {
        return open_argument[key];
    } else {
        return open_argument;
    }
}

function getArgument(key) {
    const { source } = this;
    let open_argument = source.getVariable();
    open_argument = getArguments(open_argument, '');
    return open_argument[key];
}

function setArgument(key, value) {
    const { source } = this;
    let open_argument = source.getVariable();
    open_argument = getArguments(open_argument, '');
    open_argument[key] = value;
    open_argument = JSON.stringify(open_argument);
    source.setVariable(open_argument);
    return open_argument;
}

