function checkCurrentServer() {
    try {
        var currentServer = getArgument('server') || host[0];
        java.longToast("\n\n♻️正在检测当前服务器：" + currentServer + "\n请稍等~");

        let date1 = new Date().getTime();
        let html = java.ajax(currentServer + '/');
        let date2 = new Date().getTime();
        let t = date2 - date1;
        let time = t / 1000 + 's';
        let logTime = '【' + currentServer + '】\n┋┋\n' + '响应时间：' + time;

        if (t > 5000 || !html) {
            java.longToast('\n💔【访问失败提示】\n' + 
                          '┏┅━┅━┅━┅━┅┅━┅━┅┓\n┋┋\n' + 
                          logTime + '\n┋┋\n♣️当前接口无法访问(可能被墙)♣️\n┋┋\n请切换其他接口/切换网络环境\n┋┋' + 
                          '\n┗┅━┅━┅━┅━┅┅━┅━┅┛');
        } else if (t < 1000) {
            java.longToast('\n💖【网络环境优良】\n' + 
                          '┏┅━┅━┅━┅━┅┅━┅━┅┓\n┋┋\n' + 
