}

// 切换服务器
function switchServer() {
    var servers = host;
    var currentServer = getArgument('server') || host[0];
    var currentIndex = servers.indexOf(currentServer);

    var nextIndex = (currentIndex >= 0 && currentIndex < servers.length - 1) ? (currentIndex + 1) : 0;
    var nextServer = servers[nextIndex];

    setArgument('server', nextServer);
    java.longToast("\n\n已切换到：" + nextServer + "\n\n注意：切换服务器后请重新搜索");
}

// 设置来源和tab
function sethost(index) {
    var hosts = [
        // 小说：全部用小说
        {"source":"番茄","tab":"小说","mode":3,"searchTab":"小说"},
        // 听书（小说听书）：搜索用小说，其他用有声
        {"source":"番茄","tab":"有声","mode":2,"searchTab":"小说"},
        // 真人听书：全部用有声
        {"source":"番茄","tab":"有声","mode":2,"searchTab":"有声"},
        // 漫画：全部用漫画
        {"source":"番茄","tab":"漫画","mode":8,"searchTab":"漫画"},
        // 短剧：全部用视频
        {"source":"番茄","tab":"视频","mode":11,"searchTab":"视频"}
    ];

    if (index >= 1 && index <= hosts.length) {
        var config = hosts[index-1];
        setArgument('source', config.source);
        setArgument('tab', config.tab);
        setArgument('mode', config.mode);
        setArgument('searchTab', config.searchTab);
        java.toast("已切换成：" + config.source + "-" + config.tab + "（搜索：" + config.searchTab + "）");
    }
}

